INSERT INTO "blog_posts" ("id","slug","title","excerpt","content","cover_image","category_id","tags","author","status","read_time","published_at","scheduled_at","featured","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('67e0749c-fe51-4cbc-ada2-09716ae44619','beginners-guide-first-aquarium','The Complete Beginner''s Guide to Your First Aquarium','New to fishkeeping? Here''s everything you need to set up a healthy, beautiful first tank — from choosing the tank to adding your first fish.',replace('## Welcome to the hobby\n\nSetting up your first aquarium is exciting — and easier than you think when you follow a few golden rules.\n\n### 1. Start bigger than you think\nA 2ft (55L) tank is more stable and forgiving than a tiny bowl. More water means more stable temperature and water chemistry.\n\n### 2. Cycle before you stock\nRun your filter for 2–4 weeks (or use a starter bacteria culture) before adding fish. This builds the beneficial bacteria that keep your water safe.\n\n### 3. Choose peaceful, hardy first fish\nGuppies, platies, mollies, zebra danios and corydoras are perfect starters. Add them gradually, not all at once.\n\n### 4. Feed lightly\nOnly feed what your fish finish in two minutes. Overfeeding is the #1 beginner mistake.\n\n### 5. Weekly water changes\nSwap 20–25% of the water each week and your fish will reward you with colour and health.\n\nVisit us near Eye Hospital, Kuthuparamba, and we''ll help you pick the perfect starter setup.','\n',char(10)),'https://loremflickr.com/1200/675/planted%2Caquarium/all?lock=3001','2aba53ea-4640-4af1-8658-bf09581cc766','["beginner","setup","guide"]','Happy Aquarium','published',7,1783496591,NULL,1,'The Complete Beginner''s Guide to Your First Aquarium','New to fishkeeping? Here''s everything you need to set up a healthy, beautiful first tank — from choosing the tank to adding your first fish.',NULL,NULL,NULL,0,1783496591,1783496591);
INSERT INTO "blog_posts" ("id","slug","title","excerpt","content","cover_image","category_id","tags","author","status","read_time","published_at","scheduled_at","featured","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('6fba242e-c206-4187-916a-89660d9acbf3','understanding-water-parameters','Understanding Water Parameters: pH, Ammonia & the Nitrogen Cycle','Clear water isn''t always healthy water. Learn the key parameters every fishkeeper should understand.',replace('## Invisible chemistry, visible results\n\nMost fish problems trace back to water quality. Here''s what matters.\n\n### The nitrogen cycle\nFish waste becomes **ammonia** (toxic), which bacteria convert to **nitrite** (toxic), then to **nitrate** (much safer, removed by water changes). A cycled tank has zero ammonia and nitrite.\n\n### pH\nEach species has a preferred range. Most community fish are happy at 6.8–7.6. Stability matters more than a perfect number.\n\n### Temperature\nTropical fish typically want 24–28°C. Use a reliable heater and thermometer.\n\n### Test regularly\nBring a water sample to Happy Aquarium for a **free test** and we''ll tell you exactly what your tank needs.','\n',char(10)),'https://loremflickr.com/1200/675/water%2Ctest%2Caquarium/all?lock=3002','450b78c6-3a8a-4784-96f9-d3cc63b3027e','["water quality","nitrogen cycle"]','Happy Aquarium','published',6,1783496591,NULL,0,'Understanding Water Parameters: pH, Ammonia & the Nitrogen Cycle','Clear water isn''t always healthy water. Learn the key parameters every fishkeeper should understand.',NULL,NULL,NULL,0,1783496591,1783496591);
INSERT INTO "blog_posts" ("id","slug","title","excerpt","content","cover_image","category_id","tags","author","status","read_time","published_at","scheduled_at","featured","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('81647430-baa5-43d1-9ab5-9a76b581ea0e','common-fish-diseases-treatment','Common Aquarium Fish Diseases and How to Treat Them','Spot the signs early. A practical guide to ich, fin rot, fungus and how to treat them safely.',replace('## Catch problems early\n\n### White Spot (Ich)\nTiny white grains on fins and body. Treat by raising temperature slightly and dosing an anti-ich remedy. Highly contagious — act fast.\n\n### Fin Rot\nRagged, receding fins caused by poor water quality. Improve water changes and use an antibacterial treatment.\n\n### Fungus\nCotton-wool tufts on skin. Treat with an antifungal remedy and check water parameters.\n\n### Prevention beats cure\nGood filtration, regular water changes and not overstocking prevent most disease. We stock trusted medicines and can advise on the right one for your fish.','\n',char(10)),'https://loremflickr.com/1200/675/aquarium%2Cfish/all?lock=3003','fcb279a9-4a88-452f-9657-f0e814e9eadd','["health","disease","treatment"]','Happy Aquarium','published',8,1783496591,NULL,0,'Common Aquarium Fish Diseases and How to Treat Them','Spot the signs early. A practical guide to ich, fin rot, fungus and how to treat them safely.',NULL,NULL,NULL,0,1783496591,1783496591);
INSERT INTO "blog_posts" ("id","slug","title","excerpt","content","cover_image","category_id","tags","author","status","read_time","published_at","scheduled_at","featured","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('8de4e45d-c3a6-46d8-992f-53ace38a3327','feeding-your-fish-right','Feeding Your Fish Right: What, How Much and How Often','The right diet means brighter colour, better health and cleaner water. Here''s how to get feeding right.',replace('## Variety is key\n\nDifferent fish need different diets — herbivores like plecos need veg and algae, while oscars and cichlids need protein-rich pellets.\n\n### How much?\nFeed only what''s eaten in ~2 minutes, once or twice a day. Uneaten food pollutes the water.\n\n### Mix it up\nAlternate quality flakes/pellets with frozen or live treats like bloodworm and brine shrimp for peak condition.\n\n### Colour foods\nColour-enhancing foods bring out natural reds and blues. Ask us for the best food for your species.','\n',char(10)),'https://loremflickr.com/1200/675/fish%2Cfood/all?lock=3004','9b3ac041-2e9e-45b0-9fe2-69983c64d8d8','["feeding","nutrition"]','Happy Aquarium','published',5,1783496591,NULL,0,'Feeding Your Fish Right: What, How Much and How Often','The right diet means brighter colour, better health and cleaner water. Here''s how to get feeding right.',NULL,NULL,NULL,0,1783496591,1783496591);
INSERT INTO "blog_posts" ("id","slug","title","excerpt","content","cover_image","category_id","tags","author","status","read_time","published_at","scheduled_at","featured","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('0248e97a-4021-4823-9d2b-af641e2207c7','aquascaping-basics-planted-tank','Aquascaping Basics: Designing a Beautiful Planted Tank','Turn a glass box into an underwater landscape. Learn the design principles behind stunning planted tanks.',replace('## Design with intention\n\n### The rule of thirds\nPlace your focal point (driftwood or a rock) off-centre for a natural, pleasing composition.\n\n### Layering for depth\nUse foreground, midground and background plants to create a sense of depth — short plants in front, tall behind.\n\n### Hardscape first\nArrange driftwood and rocks before planting. This is the ''bones'' of your scape.\n\n### Easy starter plants\nAnubias, java fern and amazon swords are hardy and forgiving. We stock all three plus everything you need to begin.','\n',char(10)),'https://loremflickr.com/1200/675/aquascape%2Cplanted%2Caquarium/all?lock=3005','196f2c2a-0e44-49fd-bd99-c24ac9db8ea3','["aquascaping","plants","design"]','Happy Aquarium','published',7,1783496591,NULL,1,'Aquascaping Basics: Designing a Beautiful Planted Tank','Turn a glass box into an underwater landscape. Learn the design principles behind stunning planted tanks.',NULL,NULL,NULL,0,1783496591,1783496591);
