	`category` text,
	`sort_order` integer DEFAULT 0 NOT NULL,
	`published` integer DEFAULT true NOT NULL,
	`created_at` integer,
	`updated_at` integer
);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('a18ca8fd-228e-49e9-9f78-a940fae16aaa','Do you deliver fish, or is it in-store pickup only?','You can reserve any fish on WhatsApp or by phone and pick it up in-store. For nearby areas we can arrange safe local delivery — just message us on 9947770808.','general',1,1,1783496593,1783496593);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('ba0b6fcb-cf3d-4d5e-b1af-91b8269a8630','Are your fish healthy and quarantined?','Yes. All our fish are kept in monitored, filtered systems and observed before sale. We only sell healthy, active stock and give you care guidance for each species.','general',2,1,1783496593,1783496593);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('d0d41d44-1c24-4071-9395-9287ddfdc48d','Do you sell imported fish?','We regularly stock imported species like Thailand flowerhorns and premium goldfish strains. Ask us about current imports or check the ''Imported'' tag on our fish pages.','stock',3,1,1783496593,1783496593);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('7180235b-6fc3-48c0-ace5-9567692df972','Can you help me set up a new aquarium?','Absolutely — aquarium setup is one of our services. We help you choose the tank, filter, lighting, substrate and a compatible fish community for your space and budget.','service',4,1,1783496593,1783496593);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('024b8f56-6831-4338-b54e-b4c68cf35aaf','How do I know which fish can live together?','Use our Fish Compatibility Checker and Aquarium Planner tools on this site, or just ask us. We''ll recommend a peaceful, thriving community for your tank size.','care',5,1,1783496593,1783496593);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('8e88e635-8370-44de-880d-783bef0c5f5f','What water conditions do I need?','It depends on the species — each fish page lists ideal temperature and pH. Bring a water sample for a free test and we''ll advise on conditioners and adjustments.','care',6,1,1783496594,1783496594);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('40814ff8-b02d-490e-9a9f-3baf79f00aa2','Do you offer any guarantee?','We stand behind our stock. If you have any issue shortly after purchase, contact us with photos and we''ll do our best to make it right.','general',7,1,1783496594,1783496594);
INSERT INTO "faqs" ("id","question","answer","category","sort_order","published","created_at","updated_at") VALUES('34fcfa4c-ebdb-4e23-a876-388998741c25','What are your opening hours?','We''re open 9:00 AM to 8:00 PM Monday–Saturday (till 8:30 PM Sat) and 10:00 AM to 6:00 PM on Sunday. Find us near Eye Hospital, Kuthuparamba.','general',8,1,1783496594,1783496594);
