);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('fd6203a8-56d4-413d-9f42-c9fdd6138557','guppy','Guppy','Poecilia reticulata','ad961c75-d80f-40c6-95d1-48d20eebdd42','The world''s most popular beginner fish — endlessly colourful, hardy and always active.','Guppies are vibrant livebearers that breed readily and thrive in community tanks. Males flaunt flowing, multi-coloured tails while females are larger and fuller-bodied. Available in a rainbow of strains.','Keep in groups with more females than males. Stable, slightly hard water suits them best. Feed varied flakes and the occasional live/frozen treat for peak colour.','South America',22,28,6.8,7.8,'beginner','peaceful','freshwater',40,5,'2–3 years','Omnivore — flakes, micro-pellets, brine shrimp','Excellent community fish; avoid fin-nippers and large predators.',40,30,'INR',120,'available','[{"name":"Full Red Guppy","price":45},{"name":"Blue Moscow Guppy","price":60},{"name":"Yellow Cobra Guppy","price":50},{"name":"Half-Black Guppy","price":55}]','https://loremflickr.com/900/700/guppy%2Cfish/all?lock=1001','["https://loremflickr.com/900/700/guppy%2Cfish/all?lock=7007","https://loremflickr.com/900/700/guppy%2Cfish/all?lock=7008","https://loremflickr.com/900/700/guppy%2Cfish/all?lock=7009","https://loremflickr.com/900/700/guppy%2Cfish/all?lock=7010"]',NULL,1,1,0,1,'["community","colourful","breeds easily"]',0,1,'Guppy for sale — Happy Aquarium, Kerala','The world''s most popular beginner fish — endlessly colourful, hardy and always active.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('e2e4baad-846f-40fb-82d9-99b3e66a4995','molly','Molly','Poecilia sphenops','ad961c75-d80f-40c6-95d1-48d20eebdd42','Peaceful, adaptable livebearers with a friendly nature and a taste for algae.','Mollies are sociable and easy to keep, tolerating a wide range of conditions. They graze on algae and appreciate a little aquarium salt or hard water. Great for beginners.',NULL,'Central America',24,28,7,8.2,'beginner','peaceful','freshwater',60,8,'3–5 years','Omnivore — flakes, veg matter, algae','Peaceful community; happy with guppies, platies and tetras.',50,40,'INR',80,'available','[{"name":"Black Molly","price":50},{"name":"Dalmatian Molly","price":55}]','https://loremflickr.com/900/700/molly%2Cfish/all?lock=1002','["https://loremflickr.com/900/700/molly%2Cfish/all?lock=7014","https://loremflickr.com/900/700/molly%2Cfish/all?lock=7015","https://loremflickr.com/900/700/molly%2Cfish/all?lock=7016","https://loremflickr.com/900/700/molly%2Cfish/all?lock=7017"]',NULL,1,0,0,0,'["community","algae grazer"]',0,1,'Molly for sale — Happy Aquarium, Kerala','Peaceful, adaptable livebearers with a friendly nature and a taste for algae.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('8b33c776-3c73-49b4-a552-5d71ab310acb','platy','Platy','Xiphophorus maculatus','ad961c75-d80f-40c6-95d1-48d20eebdd42','Cheerful, low-maintenance splashes of colour for any community tank.','Platies are robust, peaceful livebearers available in sunset, red-wag and blue strains. They stay small, breed easily and are perfect first fish.',NULL,'Central America',22,28,7,8,'beginner','peaceful','freshwater',45,6,'3 years','Omnivore — flakes, pellets, veg','Ideal community fish alongside guppies, mollies and corydoras.',50,40,'INR',90,'available',NULL,'https://loremflickr.com/900/700/platy%2Cfish/all?lock=1003','["https://loremflickr.com/900/700/platy%2Cfish/all?lock=7021","https://loremflickr.com/900/700/platy%2Cfish/all?lock=7022","https://loremflickr.com/900/700/platy%2Cfish/all?lock=7023","https://loremflickr.com/900/700/platy%2Cfish/all?lock=7024"]',NULL,0,0,0,1,'["community","beginner"]',0,1,'Platy for sale — Happy Aquarium, Kerala','Cheerful, low-maintenance splashes of colour for any community tank.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('3b615d73-c835-4640-bead-98a4bf67e47f','colombian-tetra','Colombian Tetra','Hyphessobrycon columbianus','76e83a92-9edb-4db5-a8f3-1306ddaf8034','A larger, silver-and-red tetra that shoals boldly and shimmers under light.','Colombian tetras have silvery-blue bodies topped with striking red fins. Active and hardy, they show best in a group of six or more.',NULL,'Colombia',23,28,5.5,7.5,'beginner','semi_aggressive','freshwater',80,6,'5 years','Omnivore — flakes, frozen foods','Keep in shoals; may nip long fins if kept in small numbers.',60,NULL,'INR',60,'available',NULL,'https://loremflickr.com/900/700/tetra%2Cfish/all?lock=1004','["https://loremflickr.com/900/700/tetra%2Cfish/all?lock=7028","https://loremflickr.com/900/700/tetra%2Cfish/all?lock=7029","https://loremflickr.com/900/700/tetra%2Cfish/all?lock=7030","https://loremflickr.com/900/700/tetra%2Cfish/all?lock=7031"]',NULL,0,0,0,0,'["shoaling","hardy"]',0,1,'Colombian Tetra for sale — Happy Aquarium, Kerala','A larger, silver-and-red tetra that shoals boldly and shimmers under light.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('31116988-4ee6-4160-8439-7634235262ae','veiltail-serpae-tetra','Veiltail Serpae Tetra','Hyphessobrycon eques','76e83a92-9edb-4db5-a8f3-1306ddaf8034','Fiery red shoaling tetras with elegant, flowing veil fins.','The veiltail serpae is a deep-red tetra with a dramatic black shoulder spot and extended finnage. Best in a tight group to spread its playful energy.',NULL,'Amazon Basin',22,27,5.5,7.5,'beginner','semi_aggressive','freshwater',70,4,'5 years','Omnivore — micro-pellets, frozen bloodworm','Shoal of 8+; keep away from slow, long-finned tankmates.',50,NULL,'INR',55,'available',NULL,'https://loremflickr.com/900/700/serpae%2Ctetra%2Cfish/all?lock=1005','["https://loremflickr.com/900/700/serpae%2Ctetra%2Cfish/all?lock=7035","https://loremflickr.com/900/700/serpae%2Ctetra%2Cfish/all?lock=7036","https://loremflickr.com/900/700/serpae%2Ctetra%2Cfish/all?lock=7037","https://loremflickr.com/900/700/serpae%2Ctetra%2Cfish/all?lock=7038"]',NULL,0,0,0,0,'["shoaling","red"]',0,1,'Veiltail Serpae Tetra for sale — Happy Aquarium, Kerala','Fiery red shoaling tetras with elegant, flowing veil fins.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('b6007df3-1a1e-4da3-8d25-72e514b4ecb3','cardinal-tetra','Cardinal Tetra','Paracheirodon axelrodi','76e83a92-9edb-4db5-a8f3-1306ddaf8034','A living neon jewel — electric blue over brilliant red, from tip to tail.','The cardinal tetra is one of the most beautiful nano fish, its full-length red stripe outshining the neon tetra. Stunning in a densely planted, dimly lit aquascape.',NULL,'Rio Negro, South America',23,28,4.5,6.8,'intermediate','peaceful','freshwater',60,3,'4–5 years','Micro-omnivore — small flakes, frozen daphnia','Peaceful shoaler; perfect with rasboras, corydoras and dwarf cichlids.',70,55,'INR',100,'available',NULL,'https://loremflickr.com/900/700/cardinal%2Ctetra/all?lock=1006','["https://loremflickr.com/900/700/cardinal%2Ctetra/all?lock=7042","https://loremflickr.com/900/700/cardinal%2Ctetra/all?lock=7043","https://loremflickr.com/900/700/cardinal%2Ctetra/all?lock=7044","https://loremflickr.com/900/700/cardinal%2Ctetra/all?lock=7045"]',NULL,1,1,0,0,'["nano","planted tank","shoaling"]',0,1,'Cardinal Tetra for sale — Happy Aquarium, Kerala','A living neon jewel — electric blue over brilliant red, from tip to tail.',NULL,NULL,NULL,0,1783496587,1783496587);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('ab149547-1134-42c7-9eec-2af3a7d082c5','red-tail-catfish','Red Tail Catfish','Phractocephalus hemioliopterus','d2756bf2-801f-43a9-be73-981515c77db0','A charismatic monster catfish for the dedicated large-tank keeper.','The red tail catfish is a striking predator with a dark body, white belly and vivid orange-red tail. Cute as a juvenile but grows very large — for experienced keepers with big systems only.','Requires a very large tank/pond as it matures. Feed meaty foods; avoid overfeeding. Powerful filtration essential.','Amazon Basin',24,30,6,7.5,'expert','aggressive','freshwater',1000,100,'15+ years','Carnivore — pellets, fish, prawns','Will eat anything it can swallow; house alone or with equally large fish.',350,NULL,'INR',12,'low_stock',NULL,'https://loremflickr.com/900/700/redtail%2Ccatfish/all?lock=1007','["https://loremflickr.com/900/700/redtail%2Ccatfish/all?lock=7049","https://loremflickr.com/900/700/redtail%2Ccatfish/all?lock=7050","https://loremflickr.com/900/700/redtail%2Ccatfish/all?lock=7051","https://loremflickr.com/900/700/redtail%2Ccatfish/all?lock=7052"]',NULL,0,0,1,0,'["monster fish","predator","large tank"]',0,1,'Red Tail Catfish for sale — Happy Aquarium, Kerala','A charismatic monster catfish for the dedicated large-tank keeper.',NULL,NULL,NULL,0,1783496588,1783496588);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('7486a1b5-7be7-4dbc-8fd4-947f16b03203','dotted-catfish','Dotted Catfish','Pimelodus pictus','d2756bf2-801f-43a9-be73-981515c77db0','The lively ''pictus'' — a silver, polka-dotted catfish that never stops exploring.','Dotted (pictus) catfish are sleek, silver and covered in black spots, with long whiskers. Active shoalers that patrol the tank day and night.',NULL,'South America',23,27,6,7.5,'intermediate','peaceful','freshwater',150,12,'8 years','Omnivore — sinking pellets, frozen foods','Peaceful with medium fish; will eat very small tankmates.',250,NULL,'INR',20,'available',NULL,'https://loremflickr.com/900/700/pictus%2Ccatfish/all?lock=1008','["https://loremflickr.com/900/700/pictus%2Ccatfish/all?lock=7056","https://loremflickr.com/900/700/pictus%2Ccatfish/all?lock=7057","https://loremflickr.com/900/700/pictus%2Ccatfish/all?lock=7058","https://loremflickr.com/900/700/pictus%2Ccatfish/all?lock=7059"]',NULL,0,0,0,0,'["active","shoaling"]',0,1,'Dotted Catfish for sale — Happy Aquarium, Kerala','The lively ''pictus'' — a silver, polka-dotted catfish that never stops exploring.',NULL,NULL,NULL,0,1783496588,1783496588);
