INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('19ca0c7a-4d82-4ef1-b261-dc94fa6a5248','zebra-fish','Zebra Fish','Danio rerio','c1082a0f-e14d-43c5-9947-aa7f9d0a516a','Tireless, striped little dashers that bring constant sparkle and motion.','Zebra danios are hardy, fast-moving shoalers striped in blue and gold. Bulletproof beginner fish that thrive in cooler community tanks and love a strong current.',NULL,'South Asia',18,26,6.5,7.5,'beginner','peaceful','freshwater',60,5,'3–4 years','Omnivore — micro flakes, small frozen foods','Superb peaceful shoaler; keep in groups of 6+.',40,30,'INR',100,'available',NULL,'https://loremflickr.com/900/700/zebra%2Cdanio%2Cfish/all?lock=1034','["https://loremflickr.com/900/700/zebra%2Cdanio%2Cfish/all?lock=7238","https://loremflickr.com/900/700/zebra%2Cdanio%2Cfish/all?lock=7239","https://loremflickr.com/900/700/zebra%2Cdanio%2Cfish/all?lock=7240","https://loremflickr.com/900/700/zebra%2Cdanio%2Cfish/all?lock=7241"]',NULL,0,0,0,1,'["shoaling","beginner","active"]',0,1,'Zebra Fish for sale — Happy Aquarium, Kerala','Tireless, striped little dashers that bring constant sparkle and motion.',NULL,NULL,NULL,0,1783496590,1783496590);
INSERT INTO "fish" ("id","slug","name","scientific_name","category_id","short_description","description","care_guide","origin","temperature_min","temperature_max","ph_min","ph_max","difficulty","aggression","water_type","tank_size_min","adult_size","lifespan","diet","compatibility","price","offer_price","currency","stock","availability","varieties","hero_image","gallery","video","featured","trending","is_imported","is_new_arrival","tags","sort_order","published","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('020241fb-265c-4c6c-b5db-a9a0ae6a71fc','black-ghost-fish','Black Ghost Fish','Apteronotus albifrons','c1082a0f-e14d-43c5-9947-aa7f9d0a516a','A mysterious, velvety-black knifefish that glides like a ribbon of shadow.','The black ghost knifefish is a captivating oddball — an elongated, jet-black nocturnal fish that swims in fluid, undulating waves and can be trained to feed from the hand.',NULL,'South America',23,28,6,7.5,'advanced','peaceful','freshwater',200,40,'10–15 years','Carnivore — bloodworm, prawns, pellets','Peaceful but eats small fish; provide caves and dim lighting.',400,340,'INR',10,'available',NULL,'https://loremflickr.com/900/700/black%2Cghost%2Cknifefish/all?lock=1035','["https://loremflickr.com/900/700/black%2Cghost%2Cknifefish/all?lock=7245","https://loremflickr.com/900/700/black%2Cghost%2Cknifefish/all?lock=7246","https://loremflickr.com/900/700/black%2Cghost%2Cknifefish/all?lock=7247","https://loremflickr.com/900/700/black%2Cghost%2Cknifefish/all?lock=7248"]',NULL,1,0,0,0,'["oddball","nocturnal","unique"]',0,1,'Black Ghost Fish for sale — Happy Aquarium, Kerala','A mysterious, velvety-black knifefish that glides like a ribbon of shadow.',NULL,NULL,NULL,0,1783496590,1783496590);
