CREATE TABLE `products` (
	`id` text PRIMARY KEY NOT NULL,
	`slug` text NOT NULL,
	`name` text NOT NULL,
	`category_id` text,
	`sku` text,
	`brand` text,
	`short_description` text,
	`description` text,
	`specs` text,
	`price` real,
