INSERT INTO "site_settings" ("id","store_name","tagline","description","phone","whatsapp","email","address_line","area","city","state","pincode","map_lat","map_lng","map_embed_url","directions_url","opening_hours","logo","favicon","socials","ga_id","meta_pixel","theme","meta_title","meta_description","keywords","og_image","canonical","noindex","created_at","updated_at") VALUES('default','Happy Aquarium','Dive into a world of living colour','Kerala''s premium aquarium store — aquarium fish, imported species, tanks, plants and everything you need to build a thriving underwater world. Near Eye Hospital, Kuthuparamba.','9947770808','919947770808','hello@happyaquarium.in','Near Eye Hospital','Kuthuparamba','Kannur','Kerala','670643',11.83064,75.56862,'https://www.google.com/maps?q=Kuthuparamba,Kerala&output=embed','https://www.google.com/maps/dir/?api=1&destination=Kuthuparamba,Kerala','{"monday":{"open":"09:00","close":"20:00"},"tuesday":{"open":"09:00","close":"20:00"},"wednesday":{"open":"09:00","close":"20:00"},"thursday":{"open":"09:00","close":"20:00"},"friday":{"open":"09:00","close":"20:00"},"saturday":{"open":"09:00","close":"20:30"},"sunday":{"open":"10:00","close":"18:00"}}',NULL,NULL,'{"instagram":"https://instagram.com/happyaquarium","facebook":"https://facebook.com/happyaquarium","youtube":"https://youtube.com/@happyaquarium","whatsapp":"https://wa.me/919947770808"}',NULL,NULL,'{"animationIntensity":"cinematic","accent":"#22d3ee"}','Happy Aquarium — Premium Aquarium Fish & Supplies in Kuthuparamba, Kerala','Aquarium fish, imported species, tanks, plants, food and accessories. Visit Happy Aquarium near Eye Hospital, Kuthuparamba, Kerala. Call 9947770808.','aquarium fish Kerala, aquarium shop Kuthuparamba, imported fish, fish tank, koi, oscar, flowerhorn, betta',NULL,NULL,0,1783496591,1783496591);
