INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('9f24bd28-991a-4ffd-937f-a7ff8ce05044','Arjun Menon','https://loremflickr.com/200/200/portrait%2Cman/all?lock=401',5,'Best aquarium shop in the Kannur area. Their fish are always healthy and the flowerhorn I bought is stunning. Great advice too!',NULL,NULL,'Thalassery',1,1,1,1783496593,1783496593);
INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('896e0ac1-851e-4a20-95fc-0b8b5a8c6a6c','Fathima Rasheed','https://loremflickr.com/200/200/portrait%2Cwoman/all?lock=402',5,'Set up my first planted tank with their help. They guided me on every accessory and the plants are thriving. Highly recommend.',NULL,NULL,'Kuthuparamba',1,1,2,1783496593,1783496593);
INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('d3063411-c70e-4272-b253-08c0e31b7114','Vishnu Prasad','https://loremflickr.com/200/200/portrait%2Cperson/all?lock=403',5,'Huge variety of imported fish. Got a pair of breeding angels and cardinal tetras — all doing brilliantly a month on.',NULL,NULL,'Mattannur',1,1,3,1783496593,1783496593);
INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('2a84a16f-5b2e-45e5-8768-5243492e241e','Sneha Nair','https://loremflickr.com/200/200/portrait%2Cgirl/all?lock=404',4,'Lovely store and very friendly staff. Their oscars have so much personality. Reserved one on WhatsApp and picked it up the next day.',NULL,NULL,'Kannur',1,1,4,1783496593,1783496593);
INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('d10f3157-bbfa-4c1b-9af3-c033f6d53fc0','Rahul Kumar','https://loremflickr.com/200/200/portrait%2Cyoung%2Cman/all?lock=405',5,'The koi selection is superb. My pond looks incredible now. They even helped with filtration advice for free.',NULL,NULL,'Panoor',1,1,5,1783496593,1783496593);
INSERT INTO "testimonials" ("id","customer_name","avatar","rating","review","image","video","location","featured","published","sort_order","created_at","updated_at") VALUES('4300ab61-dba0-4e5a-9f6d-03c5a7a6bb0c','Anjali Suresh','https://loremflickr.com/200/200/portrait%2Clady/all?lock=406',5,'Genuinely happy customers here! Healthy bettas, great prices and honest guidance. My go-to aquarium store.',NULL,NULL,'Kuthuparamba',1,1,6,1783496593,1783496593);
